    suspend fun getUserById(
        @Path("id") userId: Long
    ): Response<UserProfile>

    @GET("users/me")
    suspend fun getCurrentUser(): Response<UserProfile>

    @GET("users/search")
    suspend fun searchUsers(
        @Query("q") query: String,
        @Query("page") page: Int = 1,
        @Query("per_page") perPage: Int = 20
    ): Response<UsersResponse>
}

// --- Network Module ---

object NetworkModule {

    @Volatile
    private var retrofit: Retrofit? = null

    @Volatile
    private var currentEnvironment: Environment? = null

    private var tokenProvider: TokenProvider? = null

    fun init(environment: Environment, tokenProvider: TokenProvider) {
        this.tokenProvider = tokenProvider
        if (retrofit == null || currentEnvironment != environment) {
            synchronized(this) {
                if (retrofit == null || currentEnvironment != environment) {
                    currentEnvironment = environment
                    retrofit = createRetrofit(environment, tokenProvider)
                }
            }
        }
    }

    fun switchEnvironment(environment: Environment) {
        val tp = tokenProvider
            ?: throw IllegalStateException("NetworkModule not initialized. Call init() first.")
        synchronized(this) {
            currentEnvironment = environment
            retrofit = createRetrofit(environment, tp)
        }
    }

    private fun getRetrofit(): Retrofit {
        return retrofit
            ?: throw IllegalStateException("NetworkModule not initialized. Call init() first.")
    }

    fun getUserApiService(): UserApiService = getRetrofit().create(UserApiService::class.java)

    private fun createRetrofit(environment: Environment, tokenProvider: TokenProvider): Retrofit {
        val okHttpClient = createOkHttpClient(environment, tokenProvider)
        val gson = GsonBuilder()
            .setLenient()
            .create()

        return Retrofit.Builder()
            .baseUrl(environment.baseUrl)
            .client(okHttpClient)
            .addConverterFactory(GsonConverterFactory.create(gson))
            .build()
    }

    private fun createOkHttpClient(
        environment: Environment,
        tokenProvider: TokenProvider
    ): OkHttpClient {
        val builder = OkHttpClient.Builder()
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .writeTimeout(30, TimeUnit.SECONDS)
            .addInterceptor(AuthInterceptor(tokenProvider))
            .addInterceptor(CommonHeadersInterceptor(environment))

        // Logging for non-production environments
        if (environment != Environment.PRODUCTION) {
            val loggingInterceptor = HttpLoggingInterceptor().apply {
                level = when (environment) {
                    Environment.DEV -> HttpLoggingInterceptor.Level.BODY
                    Environment.STAGING -> HttpLoggingInterceptor.Level.HEADERS
                    else -> HttpLoggingInterceptor.Level.NONE
                }
            }
            builder.addInterceptor(loggingInterceptor)
        }

        // Certificate and public key pinning for production
        if (environment.requiresPinning) {
            val certificatePinner = CertificatePinner.Builder()
                // Pin the leaf/intermediate certificate public key hashes for api.example.com
                // Replace these SHA-256 hashes with your actual certificate pins
                .add(
                    "api.example.com",
                    "sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=" // Primary pin
                )
                .add(
                    "api.example.com",
                    "sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=" // Backup pin
                )
                .build()
            builder.certificatePinner(certificatePinner)
        }

        return builder.build()
    }
}

// --- Repository ---

class UserRepository(private val apiService: UserApiService) {

    suspend fun getUsers(page: Int = 1, perPage: Int = 20): ApiResult<UsersResponse> {
        return safeApiCall { apiService.getUsers(page, perPage) }
    }

    suspend fun getUserById(userId: Long): ApiResult<UserProfile> {
        return safeApiCall { apiService.getUserById(userId) }
    }

    suspend fun getCurrentUser(): ApiResult<UserProfile> {
        return safeApiCall { apiService.getCurrentUser() }
    }

    suspend fun searchUsers(query: String, page: Int = 1, perPage: Int = 20): ApiResult<UsersResponse> {
        return safeApiCall { apiService.searchUsers(query, page, perPage) }
    }

    private suspend fun <T> safeApiCall(call: suspend () -> Response<T>): ApiResult<T> {
        return try {
            val response = call()
            if (response.isSuccessful) {
                val body = response.body()
                if (body != null) {
                    ApiResult.Success(body)
                } else {
                    ApiResult.Error(response.code(), "Empty response body")
                }
            } else {
                val errorBody = response.errorBody()?.string() ?: "Unknown error"
                ApiResult.Error(response.code(), errorBody)
            }
        } catch (e: javax.net.ssl.SSLPeerUnverifiedException) {
            ApiResult.Error(-1, "Certificate pinning validation failed: ${e.message}", e)
        } catch (e: java.net.UnknownHostException) {
            ApiResult.Error(-1, "No internet connection", e)
        } catch (e: java.net.SocketTimeoutException) {
            ApiResult.Error(-1, "Request timed out", e)
        } catch (e: Exception) {
            ApiResult.Error(-1, e.message ?: "Unknown error", e)
        }
    }
}

